SELECT ENRL_SN, USER_ID, COURSE_SN, ORD_SN, ACCS_STRT_DT, ACCS_END_DT,
       ENRL_STAT_CD, REG_DT, MDFCN_DT
FROM COURSE_ENROLLMENT
WHERE USER_ID = #{userId}
  AND COURSE_SN = #{courseSn}

SELECT COUNT(*)
FROM COURSE_ENROLLMENT
WHERE USER_ID = #{userId}
  AND COURSE_SN = #{courseSn}
  AND ENRL_STAT_CD = 'ACTIVE'
  AND ACCS_END_DT >= CURRENT_TIMESTAMP
